const footerLinks = [{ label: "About This Site", href: "#" }];

export function Footer() {
  return (
    <footer className="border-t border-foreground/5 bg-background/5 backdrop-blur-xs">
      {/* Social Media & Links */}
      <div className="mx-auto max-w-7xl px-6 py-6">
        {/* Official Social Media */}
        <dl className="mb-5 flex items-center gap-3">
          <dt className="text-xs tracking-widest text-foreground/40">
            Official Social Media
          </dt>
          <dd className="flex items-center gap-2">
            {socialLinks.map((link) => (
              <Link
                key={link.label}
                href={link.href}
                target="_blank"
                rel="noopener noreferrer"
                className="flex h-8 w-8 items-center justify-center rounded-full text-foreground/40 transition-colors hover:bg-foreground/10 hover:text-foreground"
                aria-label={link.label}
              >
                {link.icon}
              </Link>
            ))}

            {/* 分隔线 */}
            {/* <span className="h-4 w-px bg-foreground/10" /> */}
          </dd>
        </dl>

        {/* Footer Navigation */}
        <nav className="mb-4" aria-label="页脚导航">
          <ul className="flex flex-wrap items-center gap-x-5 gap-y-1">
            {footerLinks.map((link) => (
              <li key={link.label}>
                <Link
                  href={link.href}
                  className="text-xs tracking-wide text-foreground/40 transition-colors hover:text-foreground/70"
                >
                  {link.label}
                </Link>
              </li>
            ))}
            {process.env.EMAIL && (
              <li>
                <a
                  href={`mailto:${process.env.EMAIL}`}
                  className="no-underline text-xs tracking-wide text-foreground/40 transition-colors hover:text-foreground/70"
                >
                  Contact Me
                </a>
              </li>
            )}
          </ul>
        </nav>

        {/* Copyright */}
        <p className="text-xs tracking-wide text-foreground/30">
          Copyright {new Date().getFullYear()} 静夜聆雨
        </p>
      </div>
    </footer>
  );
}
